// Static packaging artifact tests — no build tools required, no FUSE mount.
//
// Verifies that build.sh and PKGBUILD contain the structural elements that
// make the AppImage work at runtime: ORT library bundling, AppRun LD_LIBRARY_PATH,
// and the onnxruntime runtime dependency declaration.

use std::fs;
use std::path::Path;

fn project_root() -> std::path::PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR")).to_path_buf()
}

fn read_file(rel: &str) -> String {
    let path = project_root().join(rel);
    fs::read_to_string(&path).unwrap_or_else(|e| panic!("cannot read {rel}: {e}"))
}

#[test]
fn build_sh_copies_ort_so_into_appdir_lib() {
    let src = read_file("packaging/appimage/build.sh");
    assert!(
        src.contains("libonnxruntime.so") && src.contains("usr/lib/libonnxruntime.so"),
        "build.sh must copy libonnxruntime.so into usr/lib/; got:\n{src}"
    );
}

#[test]
fn build_sh_discovers_ort_via_env_var_fallback() {
    let src = read_file("packaging/appimage/build.sh");
    assert!(
        src.contains("ORT_DYLIB_PATH"),
        "build.sh must fall back to ORT_DYLIB_PATH for ORT discovery; got:\n{src}"
    );
}

#[test]
fn build_sh_writes_apprun_with_ld_library_path() {
    let src = read_file("packaging/appimage/build.sh");
    assert!(
        src.contains("AppRun") && src.contains("LD_LIBRARY_PATH"),
        "build.sh must write AppRun and set LD_LIBRARY_PATH; got:\n{src}"
    );
}

#[test]
fn build_sh_gates_linuxdeploy_on_command_v() {
    let src = read_file("packaging/appimage/build.sh");
    assert!(
        src.contains("command -v linuxdeploy"),
        "build.sh must gate linuxdeploy invocation on command -v; got:\n{src}"
    );
}

#[test]
fn pkgbuild_declares_onnxruntime_runtime_dep() {
    let src = read_file("packaging/PKGBUILD");
    assert!(
        src.contains("onnxruntime"),
        "PKGBUILD must list onnxruntime in depends; got:\n{src}"
    );
}

use vibe_attack::ui::config_app::{ConfigApp, MAX_LOG_LINES};
use vibe_attack::ui::first_run::{FirstRunState, SetupStep};

#[test]
fn first_run_complete_when_all_checks_pass() {
    let state = FirstRunState::from_checks(true, true, true, true);
    assert!(state.is_setup_complete());
}

#[test]
fn first_run_incomplete_when_config_missing() {
    let state = FirstRunState::from_checks(false, true, true, true);
    assert!(!state.is_setup_complete());
    assert!(state.steps_remaining().contains(&SetupStep::CreateConfig));
}

#[test]
fn first_run_incomplete_when_model_missing() {
    let state = FirstRunState::from_checks(true, false, true, true);
    assert!(!state.is_setup_complete());
    assert!(state.steps_remaining().contains(&SetupStep::InstallModel));
}

#[test]
fn first_run_incomplete_when_uinput_inaccessible() {
    let state = FirstRunState::from_checks(true, true, false, true);
    assert!(!state.is_setup_complete());
    assert!(state.steps_remaining().contains(&SetupStep::SetupUinput));
}

#[test]
fn first_run_incomplete_when_ptt_missing() {
    let state = FirstRunState::from_checks(true, true, true, false);
    assert!(!state.is_setup_complete());
    assert!(state.steps_remaining().contains(&SetupStep::ConfigurePtt));
}

#[test]
fn first_run_step_ordering_config_before_model() {
    let state = FirstRunState::from_checks(false, false, true, true);
    let steps = state.steps_remaining();
    let config_pos = steps.iter().position(|s| *s == SetupStep::CreateConfig);
    let model_pos = steps.iter().position(|s| *s == SetupStep::InstallModel);
    assert!(config_pos.is_some() && model_pos.is_some());
    assert!(config_pos.unwrap() < model_pos.unwrap());
}

#[test]
fn first_run_all_steps_when_fresh_install() {
    let state = FirstRunState::from_checks(false, false, false, false);
    assert_eq!(state.steps_remaining().len(), 4);
}

#[test]
fn first_incomplete_step_returns_none_when_done() {
    let state = FirstRunState::from_checks(true, true, true, true);
    assert!(state.first_incomplete_step().is_none());
}

